package arch.day52;

/**
 * Static reference tables for interviews.
 * Spring: // spring.cloud.gateway + // spring.cloud.loadbalancer + // kubernetes discovery client
 */
public class Day52Basic {

    /*
     * Plain reference tables for whiteboard interviews.
     * Pair with: kubectl get endpoints, gateway route actuator, CoreDNS metrics.
     */

    public static void main(String[] args) {
        System.out.println("=== How callers learn addresses ===");
        System.out.println("Mechanism              | Plain idea");
        System.out.println("DNS (kube Service)     | CoreDNS -> ClusterIP -> kube-proxy rules");
        System.out.println("Client registry        | App asks Eureka/Consul for instances");
        System.out.println("Mesh EDS               | Control plane pushes endpoints to Envoy sidecar");
        System.out.println("Static config file     | Breaks elastic scale; only bootstrap/dev");
        System.out.println();

        System.out.println("=== API gateway vs plain load balancer ===");
        System.out.println("Layer | Typical box        | Understands HTTP path / JWT?");
        System.out.println("L4    | NLB / TCP LB       | No — TCP streams only");
        System.out.println("L7    | API gateway        | Yes — routes, filters, auth at edge");
        System.out.println();

        System.out.println("=== Gateway duties (good vs bad) ===");
        System.out.println("Good at edge           | TLS, OAuth2/JWT check, rate limits, routing");
        System.out.println("Bad inside gateway     | Business pricing rules for every SKU");
        System.out.println();

        System.out.println("=== kubectl checks when routes fail ===");
        System.out.println("1. kubectl get endpoints <svc> -n <ns> -o wide");
        System.out.println("2. kubectl describe pod <pod> | find readiness");
        System.out.println("3. kubectl logs deploy/<gateway> --tail=200");
        System.out.println();

        System.out.println("=== Health probe meaning ===");
        System.out.println("readiness | Remove pod from Service when not safe for traffic");
        System.out.println("liveness  | Restart pod when process wedged — keep dependency checks here minimal");
    }
}

package arch.day52;

import java.util.List;

/**
 * Simulates: instance pick, gateway policy, empty discovery pool.
 * Spring mapping:
 * // Spring Cloud LoadBalancer round-robin over DiscoveryClient instances
 * // Gateway filter chain for auth before RoutePredicate
 */
public class Day52Intermediate {

    /*
     * Interview alignment (Spring / K8s):
     * // @LoadBalanced RestTemplate or WebClient resolves logical host via Spring Cloud LoadBalancer.
     * // spring.cloud.gateway routes match Path predicates then run GatewayFilter beans (auth, rate limit).
     * // In Kubernetes, kube-proxy (or CNI) programs dataplane rules from Endpoints built from readiness.
     *
     * This class deliberately stays in-memory: same ordering ideas as RR / policy / empty pool.
     *
     * Scenario map:
     * 1) Round-robin across a fixed pool (client-side pick pattern).
     * 2) Gateway rejects anonymous calls before any routing (centralized policy).
     * 3) Empty healthy list models bad readiness or full drain (502 upstream).
     * 4) Rules recap for verbal interviews.
     *
     * Deterministic only: no random, no clocks, no UUIDs.
     */

    static int rr;
    static final String[] ORDERS_POOL = {"10.1.1.1:8080", "10.1.1.2:8080", "10.1.1.3:8080"};

    static String nextOrdersInstance() {
        int idx = Math.floorMod(rr++, ORDERS_POOL.length);
        return ORDERS_POOL[idx];
    }

    static String gatewayPolicyAllow(String credential, String path) {
        if (credential == null || credential.isBlank()) {
            return "403 DENY missing credential (gateway policy)";
        }
        return "ALLOW " + path;
    }

    static String pickPaymentsUpstream(List<String> healthyHosts) {
        if (healthyHosts == null || healthyHosts.isEmpty()) {
            return "502 no healthy upstream for payments";
        }
        return healthyHosts.get(0);
    }

    public static void main(String[] args) {
        System.out.println("=== Discovery + gateway simulation ===\n");

        // --- Scenario 1: happy path — round-robin ---
        System.out.println("--- Scenario 1: happy path — round-robin across orders pool ---");
        rr = 0;
        for (int i = 0; i < 3; i++) {
            System.out.println("Route /api/orders -> " + nextOrdersInstance());
        }
        System.out.println();

        // --- Scenario 2: centralized policy ---
        System.out.println("--- Scenario 2: centralized policy at gateway ---");
        System.out.println(gatewayPolicyAllow("", "/api/orders"));
        System.out.println(gatewayPolicyAllow("Bearer demo-token", "/api/orders"));
        System.out.println();

        // --- Scenario 3: discovery / health returns nobody ---
        System.out.println("--- Scenario 3: discovery returns empty healthy set ---");
        System.out.println(pickPaymentsUpstream(List.of()));
        System.out.println();

        // --- Scenario 4: rules ---
        System.out.println("--- Scenario 4: summary rules ---");
        System.out.println("Rule 1: Gateways enforce edge auth, TLS, coarse rate limits.");
        System.out.println("Rule 2: Discovery lists must respect readiness—only healthy instances.");
        System.out.println("Rule 3: Clients need timeouts; discovery alone does not fix slow upstreams.");
        System.out.println("Rule 4: Prefer stable DNS at the edge; do not expose raw pod IPs to apps.");
    }
}

package arch.day52;

import java.util.*;

/**
 * Records + priority scoring + three stdout blocks.
 * Spring note:
 * // Order Gateway routes by predicate order — put highest-risk paths behind extra filters
 */
public class Day52Advanced {

    /*
     * Priority score ranks routes for gateway hardening: OAuth surfaces, fan-out blast radius.
     * Block 2 lists where teams usually anchor discovery (K8s DNS, mesh, hybrid registry).
     * Block 3 is an on-call cheat sheet: symptom -> first command or dashboard.
     *
     * Spring Cloud Gateway note:
     * // RouteLocatorBuilder routes order matters — place auth / TLS termination filters early.
     * // spring.cloud.kubernetes.discovery.enabled=true replaces Eureka for in-cluster apps.
     *
     * Kubernetes ops hooks:
     * // kubectl get endpoints <svc> -n <ns> -o wide
     * // kubectl get endpointslices -n <ns> --field-selector kubernetes.io/service.name=<svc>
     * // kubectl logs deploy/<gateway> -c <container> --tail=200
     *
     * Observability:
     * // Watch upstream_rq_5xx (Envoy) or Spring Cloud Gateway metrics per routeId.
     * // Correlate deploy timestamps with EndpointSlice change events.
     *
     * No randomness: scoring uses only constants in main().
     */

    record RouteRisk(String path, int downstreamFanout, boolean requiresUserOAuth) {
    }

    /*
     * Scoring is a teaching stand-in for gateway risk review:
     * - Higher downstream fan-out => more brittle timeouts and retry storms.
     * - User OAuth routes => token validation, JWKS cache, and key rotation work.
     *
     * Production checklist (voice in interviews):
     * 1) Confirm per-route timeouts and retry budgets in gateway config.
     * 2) Ensure idempotency keys for any retried non-GET from edge.
     * 3) Keep filters non-blocking; offload heavy IO to dedicated auth services.
     * 4) Canary high-priority routes first; watch error budget per routeId.
     * 5) Document partner-facing paths separately from internal ClusterIP callers.
     * 6) For multi-cluster, decide whether DNS or mesh federation owns global names.
     * 7) Validate TLS between gateway and mesh ingress when terminating at edge.
     * 8) Log structured routeId + upstream_cluster for every 5xx at gateway.
     * 9) Alert on EndpointSlice age stuck while pods churn (watch bug).
     * 10) Run game-days that drain an AZ and verify discovery convergence time.
     */

    static int routePriority(RouteRisk r) {
        int p = r.downstreamFanout() * 3;
        if (r.requiresUserOAuth()) {
            p += 12;
        }
        return p;
    }

    static void printRankedRoutes(List<RouteRisk> routes) {
        List<RouteRisk> copy = new ArrayList<>(routes);
        copy.sort(Comparator.comparingInt(Day52Advanced::routePriority).reversed());
        for (RouteRisk r : copy) {
            System.out.println(r.path() + " priority=" + routePriority(r));
        }
    }

    public static void main(String[] args) {

        System.out.println("=== Block 1: route complexity score ===");
        System.out.println("Higher priority => review gateway filters, timeouts, and canary first.");
        System.out.println();
        printRankedRoutes(List.of(
                new RouteRisk("/api/checkout", 5, true),
                new RouteRisk("/api/catalog", 2, false),
                new RouteRisk("/api/admin", 1, true)
        ));
        System.out.println();

        System.out.println("=== Block 2: discovery pattern cheat sheet ===");
        System.out.println("Pure Kubernetes microservices: Service DNS + Ingress or Gateway API.");
        System.out.println("Spring Cloud on VMs + K8s mix: Consul or Eureka until full migration.");
        System.out.println("Strict mTLS everywhere: mesh data plane + gateway at trust boundary.");
        System.out.println("Partner HTTP APIs: public gateway + JWT + WAF, never raw ClusterIP DNS.");
        System.out.println();

        System.out.println("=== Block 3: gateway / discovery decision reference ===");
        System.out.println("Symptom                               | First move");
        System.out.println("502 spike after rollout               | kubectl get endpoints + readiness");
        System.out.println("Clients hit stale pods                | shorten LB cache or recycle pools");
        System.out.println("Gateway CPU low but p99 high          | TLS/JWT filter or upstream latency");
        System.out.println("DNS storms                            | raise TTL carefully or cache in client");
        System.out.println("Cross-cluster routing                 | multi-cluster gateway or mesh federation");
        System.out.println("Unknown caller abuse                  | OAuth2 client credentials + per-key quota");
        System.out.println("Need path-based canary                | weighted route or Flagger + metrics");
        System.out.println("Spring upgrade breaks discovery       | align Spring Cloud BOM with Boot");
        System.out.println("Huge Service cardinality              | endpoint subsetting / split services");
        System.out.println("Debugging misses trace                | inject traceparent at gateway filter");
    }
}

