package arch.day52;

import java.util.*;

/**
 * Day 52 assignment: routing table + service registry + gateway API-key policy.
 * Mirrors "Routing, discovery, and centralized policies" from assignments_phase6.json.
 */
public class Day52Exercise {

    static final class Instance {
        final String hostPort;
        final boolean healthy;

        Instance(String hostPort, boolean healthy) {
            this.hostPort = hostPort;
            this.healthy = healthy;
        }
    }

    static final class Registry {
        private final Map<String, List<Instance>> byService = new LinkedHashMap<>();

        void register(String serviceId, Instance instance) {
            byService.computeIfAbsent(serviceId, k -> new ArrayList<>()).add(instance);
        }

        String pickFirstHealthy(String serviceId) {
            List<Instance> list = byService.get(serviceId);
            if (list == null || list.isEmpty()) {
                return "NO_INSTANCES_REGISTERED";
            }
            for (Instance i : list) {
                if (i.healthy) {
                    return i.hostPort;
                }
            }
            return "NO_HEALTHY_INSTANCE";
        }
    }

    static String handleRequest(Registry reg,
                                LinkedHashMap<String, String> routes,
                                String apiKey,
                                String path) {
        if (apiKey == null || apiKey.isBlank()) {
            return "403 policy: missing X-Api-Key";
        }
        for (Map.Entry<String, String> e : routes.entrySet()) {
            if (path.startsWith(e.getKey())) {
                String svc = e.getValue();
                String upstream = reg.pickFirstHealthy(svc);
                return "ROUTE " + path + " -> " + svc + " -> " + upstream;
            }
        }
        return "404 no route";
    }

    public static void main(String[] args) {
        Registry reg = new Registry();
        reg.register("payments", new Instance("10.2.0.1:8081", true));
        reg.register("payments", new Instance("10.2.0.2:8081", false));

        LinkedHashMap<String, String> routes = new LinkedHashMap<>();
        routes.put("/api/payments", "payments");
        routes.put("/api/orders", "orders");

        System.out.println("=== Assignment: routing + discovery + gateway policy ===\n");
        System.out.println(handleRequest(reg, routes, "key-001", "/api/payments/42"));
        System.out.println(handleRequest(reg, routes, "", "/api/payments/42"));
        System.out.println(handleRequest(reg, routes, "key-001", "/api/orders/1"));
        reg.register("orders", new Instance("10.3.0.1:8090", true));
        System.out.println(handleRequest(reg, routes, "key-001", "/api/orders/1"));
    }
}

